function stripToTOC(nodes) {
  return nodes.map(node => ({
    node_id: node.node_id,
    title: node.title,
    start_index: node.start_index,   // was page_index
    end_index: node.end_index,       // new — exact section boundary
    description: node.summary,       // was node.text
    children: (node.nodes || []).map(c => ({
      node_id: c.node_id,
      title: c.title,
      start_index: c.start_index,
      end_index: c.end_index
    }))
  }));
}

output = {
  toc_json: JSON.stringify(stripToTOC(tree)),
  node_count: tree.length
};

const tree = {{postgresNode_817.output.queryResult[0].tree}}
const rawText = {{postgresNode_817.output.queryResult[0].raw_text}};
const nodeList = {{InstructorLLMNode_432.output.node_list}};

// Flatten tree to node_id map
function flattenTree(nodes, map = {}) {
  for (const n of nodes) {
    map[n.node_id] = n;
    if (n.nodes && n.nodes.length > 0) flattenTree(n.nodes, map);
  }
  return map;
}

const nodeMap = flattenTree(tree);
const selectedNodes = nodeList.map(id => nodeMap[id]).filter(Boolean);

// PageIndex: use exact start_index → end_index range (no guessing)
const retrieved = selectedNodes.map(node => {
  const startPage = node.start_index || 1;
  const endPage = node.end_index || startPage + 2;
  let pageContent = "";

  for (let p = startPage; p <= Math.min(endPage, startPage + 4); p++) {
    const marker = `[PAGE ${p}]`;
    const nextMarker = `[PAGE ${p + 1}]`;
    if (rawText.includes(marker)) {
      const start = rawText.indexOf(marker) + marker.length;
      const end = rawText.includes(nextMarker)
        ? rawText.indexOf(nextMarker)
        : Math.min(start + 3000, rawText.length);
      pageContent += rawText.slice(start, end).trim() + "\n\n";
    }
  }

  return {
    node_id: node.node_id,
    title: node.title,
    start_index: node.start_index,
    end_index: node.end_index,
    summary: node.summary,           // was node.text
    page_content: pageContent.trim() || node.summary
  };
});

const context = retrieved
  .map(n => `[Section: "${n.title}" | Pages: ${n.start_index}–${n.end_index}]\n${n.page_content}`)
  .join("\n\n---\n\n");

output = { context, retrieved_nodes: retrieved };
